  webpack: (config, { isServer }) => {
    if (isServer) {
      config.externals = [
        ...(config.externals || []),
        'net',
        'tls',
        'dns',
        'crypto',
        'fs/promises',
        'path',
      ];
    }
    return config;
  },
};

module.exports = nextConfig;
```

